"""
MKT Original Commentary — Luke chapters 19–20
Run: python3 scripts/zc-original-luke-19-20.py

Source data used:
- data/interlinear/luke.json
- data/translation/draft/mediating/luke.json
- data/translation/glossary-greek.json

Key decisions in this range:
- 19:2: architelōnēs (chief tax collector) is unique to Luke; implies Zacchaeus
  supervised a revenue district, not merely a single customs post.
- 19:9: "semeron sōtēria tō oikō toutō egeneto" — Luke's soteriology is
  household-inclusive; the "son of Abraham" declaration restores covenant status.
- 19:11-27: The Parable of the Pounds differs from Matthew's Talents in context
  (Jerusalem near) and detail (rejected nobleman = political allegory for
  Archelaus's failed petition in Rome, 4 BCE).
- 19:38: Luke adds "Peace in heaven" to Ps 118:26; contrast with 2:14 "peace on
  earth" — the triumphal entry announces the convergence of the two.
- 20:17: Ps 118:22 citation; the "stone" rejected by builders becomes the
  cornerstone — Jesus interprets the vineyard parable with a second OT text.
- 20:37-38: Moses's burning-bush argument for resurrection is a fortiori reasoning
  from covenant grammar: YHWH is God of the living, present-tense.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

LUKE = {
  "19": {
    "1": '<p><strong>Kai eiselthōn diērcheto tēn Iericho</strong> — entering, he was passing through Jericho — <em>Iericho</em> (Jericho) was the final major stop on the ascent road from the Jordan valley to Jerusalem; ~27km separated it from Jerusalem, with a 1,000m altitude gain. <em>Eiselthōn diērcheto</em> (entering, was passing through — two verbs indicating momentary entry into a through-passage) sets up the dramatic interruption: Jesus was not stopping in Jericho but is detained by two encounters (blind Bartimaeus in 18:35-43; Zacchaeus here). The Jericho scenes are Luke\'s final station before the Jerusalem entry.</p>',
    "2": '<p><strong>kai idou anēr onomati kaloumenos Zakchaios, kai autos ēn architelōnēs kai autos plousios</strong> — and there was a man called by name Zacchaeus, and he was a chief tax collector and wealthy — <em>Zakchaios</em> is the Greek form of the Hebrew <em>Zakkay</em> (pure, innocent — a name whose irony Luke\'s audience would appreciate). <em>Architelōnēs</em> (chief tax collector — a compound unique to Luke in the NT; <em>archi-</em> = head, chief + <em>telōnēs</em> = tax collector) implies a supervisory role over a revenue district, not merely a single customs booth. Jericho was a wealthy customs location on the balsam-trade route; <em>plousios</em> (wealthy) is the third descriptor, completing his social profile: named, powerful, rich.</p>',
    "3": '<p><strong>kai ezētei idein ton Iēsoun tis estin kai ouk ēdynato apo tou ochlou, hoti tē hēlikia mikros ēn</strong> — he was seeking to see who Jesus was and could not because of the crowd, because he was small in stature — <em>ezētei idein</em> (was seeking to see — imperfect of persistent effort) before the encounter begins. <em>Tis estin</em> (who he is) — the same Christological question the storm disciples asked (8:25); Zacchaeus is asking the right question. <em>Tē hēlikia mikros</em> (small in stature — <em>hēlikia</em> can mean age or stature; here physical height, confirmed by v.4). The crowd that surrounds Jesus is the immediate obstacle; Zacchaeus\'s social marginality (tax collectors were despised) may have meant no one would let him through.</p>',
    "4": '<p><strong>kai prodramōn eis to emprosthen anebē epi sykomorean</strong> — running ahead to the front, he climbed a sycamore-fig tree — <em>prodramōn</em> (running ahead — aorist participle of proactive initiative; an undignified act for a wealthy official in honor-based Mediterranean culture). <em>Sykomorea</em> (sycamore-fig — <em>Ficus sycomorus</em>, different from the sycamore of temperate climates; a spreading tree with low branches accessible for climbing, common in the Jericho valley). The wealthy tax official climbing a tree to see Jesus inverts the expected social hierarchy: the powerful man humbles himself to a childlike position. <strong>hina idē auton, hoti ekeinēs emellen diercheisthai</strong> — to see him because he was about to pass through that way.</p>',
    "5": '<p><strong>kai hōs ēlthen epi ton topon, anablepsas ho Iēsous eipen pros auton, Zakchaie, speusas kataba</strong> — when he came to the place, looking up Jesus said to him: Zacchaeus, hurry and come down — Jesus looks up (<em>anablepsas</em> — the verb for restored sight in 18:41-43; the Bartimaeus healing is still fresh in the narrative) and addresses Zacchaeus by name: divine initiative from below. <strong>sēmeron gar en tō oikō sou dei me meinai</strong> — for today it is necessary for me to remain in your house — <em>dei</em> (divine necessity — Luke\'s compulsion word) — the stay in Zacchaeus\'s house is not social preference but divine appointment. <em>Sēmeron</em> (today — Luke\'s eschatological present; cf. 4:21; 23:43) marks the moment of salvation\'s arrival.</p>',
    "6": '<p><strong>kai speusas katebē kai hypedexato auton chairōn</strong> — hurrying he came down and welcomed him rejoicing — the speed and joy of the response: <em>speusas</em> (hurrying — the same root as the angels\' urgency in 2:16; the shepherds who "went with haste") and <em>chairōn</em> (rejoicing — the characteristic Lukan response to grace). <em>Hypedechomai</em> (to welcome, receive as a guest — a compound of <em>dechomai</em>: to accept, receive; the posture of hospitality and humble reception) — Zacchaeus is not a passive recipient but an active welcomer. The reception mirrors the prodigal\'s father (15:20) and the host who runs to meet the returning son.</p>',
    "7": '<p><strong>kai idontes pantes diegoggyzon legontes hoti Para hamartōlō andri eisēlthen katalysai</strong> — all seeing it were murmuring, saying: he has gone in to stay with a sinful man — <em>diegoggyzon</em> (were murmuring, grumbling thoroughly — the dia-prefix intensifies; the LXX term for Israel\'s wilderness complaints, cf. 5:30) from the entire crowd. <em>Hamartōlō andri</em> (a sinful man) — the social verdict on the tax collector; he is categorically excluded from table-fellowship for those maintaining purity. The crowd\'s grumble is the same as the Pharisees\' in 5:30 ("Why do you eat and drink with tax collectors and sinners?") — the question the next three verses will answer definitively.</p>',
    "8": '<p><strong>statheis de Zakchaios eipen pros ton Kyrion, Idou ta hēmisē mou tōn hyparchontōn, Kyrie, tois ptōchois didōmi</strong> — Zacchaeus stood and said to the Lord: behold, half of my possessions, Lord, I give to the poor — <em>statheis</em> (standing — taking a public, formal stance) marks a public declaration. <em>Ta hēmisē</em> (half — not all, which would be poverty, but the substantial half, exceeding the legal restitution requirement). The present tense <em>didōmi</em> (I give — not "I will give") indicates a current practice or an immediate decision, not a future promise. <strong>kai ei tinos ti esykophantēsa, apodidōmi tetraploun</strong> — and if I defrauded anyone of anything, I repay fourfold — <em>sykophantō</em> (to defraud, extort — cf. 3:14) followed by fourfold restitution exceeds the Torah\'s requirement (Exod 22:1 four-fold for stolen sheep; Lev 6:5 requires 100% + 20%).</p>',
    "9": '<p><strong>eipen de pros auton ho Iēsous, Sēmeron sōtēria tō oikō toutō egeneto</strong> — Jesus said to him: today salvation has come to this house — <em>Sēmeron sōtēria egeneto</em> (today salvation happened/came into existence — aorist of accomplished fact) — <em>sōtēria</em> (salvation) has arrived in the person of Jesus; it came with him when he entered. <em>Tō oikō toutō</em> (to this house) — household-inclusive salvation: Zacchaeus\'s whole household is encompassed (cf. Acts 16:31; 18:8 where household salvation becomes normative in Acts). <strong>kathoti kai autos huios Abraam estin</strong> — because he also is a son of Abraham — the "son of Abraham" declaration (cf. 13:16 "daughter of Abraham") restores Zacchaeus\'s covenant status that his profession had forfeited in popular estimation; the declaration is divine, not social.</p>',
    "11": '<p><strong>Akouontōn de autōn tauta prostheis eipen parabolēn</strong> — as they were hearing these things he added a parable — the parable of the Pounds is told because of a mistaken expectation: <strong>dia to engys einai Ierousalēm auton kai dokein autous hoti parachrēma mellei hē basileia tou Theou anaphainesthai</strong> — because he was near Jerusalem and they thought the kingdom of God was going to appear immediately — <em>parachrēma</em> (immediately, at once — Luke\'s healing-stamp word applied here to eschatological expectation) captures the disciples\' imminent-kingdom excitement. The parable corrects this: there is an intervening period (the nobleman going to a distant country) before the kingdom\'s full arrival.</p>',
    "12": '<p><strong>eipen oun, Anthrōpos tis eugenēs eporeuthē eis chōran makran labein heautō basileian kai hypostrephai</strong> — a man of noble birth went to a distant country to receive for himself a kingdom and to return — <em>eugenēs</em> (well-born, of noble lineage — the aristocratic qualifier) and the journey to receive a kingdom in a distant land evokes the historical precedent of Archelaus, who in 4 BCE traveled to Rome to receive confirmation of his inheritance of Judea from Caesar Augustus (Josephus, Ant. 17.299-303). A delegation of Jews had petitioned against him (Josephus, Ant. 17.300) — precisely the pattern of v.14. The allegory maps the absent nobleman onto Jesus\'s ascension and return.</p>',
    "13": '<p><strong>kalesas de deka doulous heautou edōken autois deka mnas kai eipen pros autous, Pragmateusasthe en hō erchomai</strong> — calling ten of his servants he gave them ten minas and said to them: do business until I come — <em>mna</em> (mina — a Greek monetary unit = 100 drachmas = ~3.3 months\' wages for a laborer; vs. Matthew\'s <em>talanta</em> which were 60 minas each). Ten servants receive one mina each — a modest but real commission. <em>Pragmateuomai</em> (to do business, trade, engage in commerce) is a commercial term for active investment. The instruction "until I come" (<em>en hō erchomai</em>) marks the period of the absent king as the time for faithful stewardship — an ecclesiological comment on the church\'s mandate in the interim.</p>',
    "14": '<p><strong>hoi de politai autou emisoun auton kai apesteilan presbeiav opisō autou legontes, Ou thelomen touton basileusai eph hēmas</strong> — but his citizens hated him and sent a delegation after him saying: we do not want this man to reign over us — <em>emisoun</em> (were hating — imperfect of continuous hatred), <em>presbeia</em> (a delegation, embassy — the formal ambassadorial term for an official delegation sent to a higher authority). The historical parallel with the anti-Archelaus delegation is exact (Josephus, Ant. 17.300: a delegation of fifty Jews sent to Augustus). In the parable\'s allegory, the rejection of the nobleman is the rejection of Jesus by the Jerusalem establishment, climaxing in the Passion.</p>',
    "15": '<p><strong>kai egeneto en tō epanelthein auton labonta tēn basileian kai eipen phōnēthēnai autō tous doulous toutous</strong> — when he returned having received the kingdom, he commanded that these servants be called — the return completes the allegory of the ascension-and-parousia: the nobleman (Jesus) has received the kingdom (exaltation to God\'s right hand) and returns to reckon with his servants. <strong>hina gnoi ti diepragmateusanto</strong> — in order to know what business they had conducted — <em>diapragmateuomai</em> (to conduct business thoroughly, trade diligently — compound of <em>dia</em> + <em>pragmateuomai</em>) is the accounting moment: what the servants did with the commission during the absent period.</p>',
    "16": '<p><strong>parGeneto de ho prōtos legōn, Kyrie, hē mna sou deka mnas prosērgasato</strong> — the first came saying: Lord, your mina has earned ten minas more — <em>prosērgasato</em> (earned in addition, produced as a surplus — from <em>prosergazomai</em>: to work toward in addition; a commercial production term). Ten-fold return on a single mina is exceptional; the servant\'s use of "your mina" (<em>hē mna sou</em>) is the key theological detail — the servant acknowledges the capital as belonging to the master, not himself. The faithful steward returns the master\'s investment with return, not the investment alone.</p>',
    "17": '<p><strong>kai eipen autō, Euge, agathe doule, hoti en elachistō pistos egenou, isthi exousian echōn epanō deka poleōn</strong> — well done, good servant! because you were faithful in a very small matter, be having authority over ten cities — <em>Euge</em> (well done! — a Greek exclamation of approval; Matthew\'s parallel has "well done" differently). <em>Elachistō</em> (the least, smallest thing — a mina relative to a kingdom is <em>elachiston</em>) — the faithful management of a small commission earns authority over ten cities. The scale of reward exceeds the scale of the commission: faithful stewardship in the interim period earns eschatological authority in the kingdom. The reward is increased responsibility, not rest.</p>',
    "18": '<p><strong>kai ēlthen ho deuteros legōn, Hē mna sou, Kyrie, epoiēsen pente mnas</strong> — the second came saying: your mina, Lord, has made five minas — the second servant\'s return is proportionally strong (5x) though less than the first (10x). Like the first, he uses "your mina" — acknowledging the master\'s ownership. Luke does not record the same verbal commendation as Matthew\'s parallel (Mt 25:23 "well done") but the reward follows the same proportional logic.</p>',
    "19": '<p><strong>eipen de kai toutō, Kai sy epanō ginou pente poleōn</strong> — he said also to this one: you also take charge of five cities — five cities for five-mina profit: the reward is proportional to return. The pattern of proportional reward (10 cities for 10 minas, 5 cities for 5 minas) establishes the kingdom\'s economy of faithfulness: the master does not flatten outcomes but calibrates recognition to the servant\'s results. The political-administrative character of the reward (governing cities) points to the disciples\' eschatological role in the renewed creation (cf. Mt 19:28; Rev 20:4-6).</p>',
    "20": '<p><strong>kai ho heteros ēlthen legōn, Kyrie, idou hē mna sou hēn eichon apokeimenēn en soudarion</strong> — the other came saying: Lord, behold your mina which I had stored in a cloth — <em>apokeimenēn</em> (stored away, laid up — perfect passive participle: kept in a fixed, unchanged state) — the mina returned is precisely the mina given; nothing gained, nothing lost. <em>Soudariov</em> (cloth, napkin — a Latin loanword from <em>sudarium</em>, a sweat cloth) was not a secure storage vessel; it suggests informal, low-security preservation rather than banking. The contrast with the first servants\' active trading is stark: this servant did nothing with the commission.</p>',
    "21": '<p><strong>ephoboumēn gar se, hoti anthrōpos austēros ei, aireis ho ouk ethēkas kai therizeis ho ouk espeiras</strong> — for I was afraid of you, because you are an exacting man; you take up what you did not set down and reap what you did not sow — <em>austēros</em> (austere, strict, exacting — from <em>austēros</em> meaning dry, harsh, stringent; used of a demanding master) is the servant\'s characterization of the master. The reaping-what-one-didn\'t-sow idiom describes appropriating others\' labor — the servant\'s stated reason for non-investment is fear of the master\'s expectations, which ironically makes his inaction even more culpable: if the master is demanding, more reason to produce.</p>',
    "22": '<p><strong>legei autō, Ek tou stomatos sou krinō se, ponēre doule</strong> — he says to him: from your own mouth I judge you, wicked servant — <em>Ek tou stomatos sou krinō se</em> (from your own mouth I judge you) — the servant\'s own stated beliefs about the master are turned into the basis of judgment. <strong>ēdeis hoti egō anthrōpos austēros eimi, airōn ho ouk ethēka kai therizōn ho ouk espeira</strong> — you knew that I am an exacting man, taking what I did not set down and reaping what I did not sow — if the servant\'s assessment of the master was correct, his failure to invest was the more inexcusable: the most exacting possible master would demand returns, not merely preservation of capital.</p>',
    "23": '<p><strong>kai dia ti ouk edōkas mou to argyrion epi trapezan</strong> — and why therefore did you not give my money to the bank? — <em>trapeza</em> (table, banker\'s table — the money-changer\'s or banker\'s counter; the term for banking institutions in the Hellenistic world, cf. the temple money-changers\' <em>trapezai</em> in Mt 21:12). The minimum acceptable action was deposit for interest: even without active trading, the servant could have made something. <strong>kagō elthōn syn tokō an auto epraxa</strong> — and I, coming, would have collected it with interest — <em>tokos</em> (interest on a loan — literally "offspring," money that grows; cf. Exod 22:25; Deut 23:19-20 which restricted interest among Israelites but not in commercial Gentile contexts) — even modest interest would have been better than no return.</p>',
    "24": '<p><strong>kai tois parestōsin eipen, Arate ap autou tēn mnan kai dote tō tas deka mnas echonti</strong> — and to those standing by he said: take the mina from him and give it to the one who has ten minas — the redistribution is the application of the principle stated in v.26. <em>Parestōsin</em> (those standing by) — the bystanders at the judgment scene who carry out the king\'s orders. The mina taken from the unproductive servant goes to the most productive — not to the second servant with five but to the first with ten. The logic of kingdom economy: resources flow toward demonstrated fruitfulness, not toward potential or need.</p>',
    "25": '<p><strong>kai eipan autō, Kyrie, echei deka mnas</strong> — they said to him: Lord, he already has ten minas — the objection of the bystanders is the expected human reaction: fairness would suggest giving to one with less, not more. The objection receives no rebuke but prompts the economic principle of v.26. Luke includes this exchange (absent from Matthew) to create space for the explicit principle-statement; the objection voices what the audience is thinking.</p>',
    "26": '<p><strong>legō hymin hoti panti tō echonti dothēsetai, apo de tou mē echontos kai ho echei arthēsetai</strong> — I tell you that to everyone who has, more will be given; but from the one who does not have, even what he has will be taken away — the principle of kingdom economy (cf. 8:18; Mk 4:25; Mt 13:12; 25:29): productive use of what is given generates increase; non-use leads to loss. The principle is not about initial endowment but about faithfulness with what one has been given. In the parable\'s context: those who stewarded the commission faithfully accumulate; those who did not lose even the original. The principle operates in the eschatological accounting, not in material economy.</p>',
    "27": '<p><strong>plēn tous echthrous mou toutous tous mē thelēsantas me basileusai ep autous agagete hōde kai katasphaxate autous emprosthen mou</strong> — but as for these enemies of mine who did not want me to reign over them, bring them here and slaughter them before me — the king\'s command regarding the rebellious citizens (v.14) applies the political allegory to its historical conclusion: the anti-Archelaus delegation failed and Archelaus was confirmed; in the parable\'s deeper logic, this anticipates Jerusalem\'s destruction in 70 CE as the consequence of rejecting the Messiah-King. The violence of the image is the parable\'s realism about political consequences, not a pastoral instruction.</p>',
    "28": '<p><strong>kai tauta eipōn eporeueto emprosthen anabainōn eis Ierousalēm</strong> — having said these things he was going ahead, going up to Jerusalem — <em>emprosthen</em> (ahead, in front) — Jesus leads the ascent; the disciples follow. <em>Anabainōn eis Ierousalēm</em> (going up to Jerusalem) — the geographical-theological ascent: from Jericho (-250m below sea level) to Jerusalem (+750m above sea level) is a 1,000m climb, always described as "going up" (<em>anabainō</em>). The journey narrative (9:51) that has been building since the Galilee chapters now reaches its destination: the next step after the parable is the entry into the city.</p>',
    "29": '<p><strong>kai egeneto hōs ēggisen eis Bēthphagē kai Bēthanian pros to oros to kaloumenon Elaiōn</strong> — when he came near to Bethphage and Bethany at the mount called the Mount of Olives — <em>Bēthphagē</em> (Bethphage — "house of unripe figs," a village on the eastern slope of the Mount of Olives) and <em>Bēthanian</em> (Bethany — the home of Mary, Martha, and Lazarus; ~2km from Jerusalem). <em>Oros ... Elaiōn</em> (Mount of Olives) is the ridge east of Jerusalem across the Kidron Valley; Zech 14:4 places YHWH\'s feet there at the eschaton, giving the mountain eschatological significance. <strong>apesteilen dyo tōn mathētōn</strong> — he sent two of the disciples — the dual-witness commission (Deut 19:15).</p>',
    "30": '<p><strong>Hypagete eis tēn katenanti kōmēn, en hē eisporeuomenoi heurēsete pōlon dedemenon, eph hon oudeis pōpote anthrōpōn ekathisen</strong> — go into the village opposite, in which entering you will find a colt tied, on which no one has ever sat — <em>pōlos</em> (a young animal — in this context a young donkey; the LXX uses <em>pōlos</em> for the donkey\'s foal of Zech 9:9). <em>Eph hon oudeis pōpote anthrōpōn ekathisen</em> (on which no one has ever sat) — an unridden animal was considered sacred and appropriate for holy purposes (cf. Num 19:2 the unworked red heifer; 1 Sam 6:7 the unworked cows). The unused animal is fitting for a king\'s ride. <strong>kai lysantes auton agagete</strong> — and untying him, bring him.</p>',
    "31": '<p><strong>kai ean tis hymas erōtā, Dia ti lyete, houtōs ereite, Hoti ho Kyrios autou chreian echei</strong> — and if anyone asks you: why are you untying it? say thus: because the Lord needs it — <em>ho Kyrios</em> (the Lord) is used absolutely without further identification — the title the post-resurrection community used for the risen Jesus (cf. Acts 2:36). <em>Chreian echei</em> (has need, needs it) — the Lord\'s need is the authorization that overrides the owners\' ordinary property rights. The pre-arranged answer (or a miraculous provision of the right words) demonstrates Jesus\'s sovereign knowledge of what will happen and his authority to commandeer what he needs for the messianic entry.</p>',
    "32": '<p><strong>apelthontes de hoi apestalmenoi heuron kathōs eipen autois</strong> — going, those sent found it exactly as he had told them — <em>kathōs eipen autois</em> (just as he told them) is the verification of prophetic knowledge: Jesus\'s instruction was not a guess but foreknowledge. Luke uses this verification pattern in 22:13 (the Passover room) to frame both the triumphal entry and the Last Supper as divinely arranged events. The disciples\' experience of finding things "just as he said" is itself a discipleship formation: training them to trust Jesus\'s foreknowledge in preparation for the Passion\'s apparent chaos.</p>',
    "33": '<p><strong>lyontōn de autōn ton pōlon eipan hoi kyrioi autou pros autous, Ti lyete ton pōlon</strong> — as they were untying the colt, its owners said to them: why are you untying the colt? — <em>kyrioi autou</em> (its owners — plural) — the colt has multiple owners (perhaps a family). The challenge is natural and expected; the disciples have been prepared for it (v.31). Luke\'s inclusion of the encounter makes the scene concrete: the disciples face an actual challenge and respond with the prepared answer. The owners\' question is not hostile but naturally curious; what follows (v.34) is their simple acceptance of the answer.</p>',
    "34": '<p><strong>hoi de eipan, Ho Kyrios autou chreian echei</strong> — they said: the Lord needs it — the identical phrase from v.31 is repeated verbatim: the prepared answer is given, word for word. Luke\'s repetition is narrative confirmation: what was predicted was enacted exactly. The owners\' acceptance of this explanation without further question may indicate: (a) they knew Jesus, (b) they recognized a divine commission, or (c) Luke abbreviates their response. In any case, the colt is released; the messianic entry can proceed.</p>',
    "35": '<p><strong>kai ēgagon auton pros ton Iēsoun kai epiriptes autōn ta himatia epi ton pōlon epebibasan ton Iēsoun</strong> — they brought it to Jesus and throwing their garments on the colt they set Jesus on it — <em>epiriptes</em> (throwing over, casting on) their garments (<em>himatia</em>) on the colt creates the impromptu saddle; the gesture is simultaneously practical and honorific. The placing of garments under a new king echoes 2 Kgs 9:13 where the generals spread their garments under Jehu when proclaiming him king. <em>Epebibasan</em> (set him on it) — the disciples act as royal attendants placing the king on his mount.</p>',
    "36": '<p><strong>poreuomenou de autou hypestrōnnyon ta himatia autōn en tē hodō</strong> — as he was going, they were spreading their garments on the road — <em>hypestrōnnyon</em> (were spreading under, strewing — imperfect of continuous action throughout the procession) the garments on the road — again the royal-installation gesture (2 Kgs 9:13). Matthew (21:8) and Mark (11:8) add branches cut from trees; Luke mentions only garments, perhaps for literary simplicity or because branches were less common in the Jericho/Olivet corridor. The road-spreading creates a royal carpet for the Messiah-King\'s entrance.</p>',
    "37": '<p><strong>eggizovtos de autou ēdē pros tē katabasei tou orous tōn Elaiōn ērxanto hapan to plēthos tōn mathētōn chairovtes ainein ton Theon phōnē megalē</strong> — as he was already approaching the descent of the Mount of Olives, the whole multitude of disciples began rejoicing to praise God with a great voice — <em>katabasis</em> (descent, the downward slope) — on the descent from the Mount of Olives, Jerusalem comes into view across the Kidron; this is the moment of the crowd\'s eruption. <em>Hapan to plēthos tōn mathētōn</em> (the whole crowd of disciples — not just the Twelve but the wider disciple community) begins the acclamation. <strong>peri pasōn hōn eidon dynameōn</strong> — for all the works of power they had seen — the praise is grounded in witnessed miracles.</p>',
    "38": '<p><strong>legontes, Eulogēmenos ho erchomenos ho basileus en onomati Kyriou</strong> — saying: blessed is the king who comes in the name of the Lord — Ps 118:26 (LXX) is the citation (the final verse of the Hallel, sung at Passover). Luke uniquely inserts <em>ho basileus</em> (the King) into the Psalm citation, making the messianic application explicit. <strong>en ouranō eirēnē kai doxa en hypsistois</strong> — peace in heaven and glory in the highest — Luke\'s version replaces the crowd\'s "Hosanna" (Matthew, Mark, John) with a heavenly doxology that mirrors the birth announcement (2:14: "glory to God in the highest and on earth peace"). The triumphal entry announces the convergence of heaven and earth: peace that was "on earth" at the birth is now "in heaven" as the King approaches his throne through the cross.</p>',
    "39": '<p><strong>kai tines tōn Pharisaiōn apo tou ochlou eipan pros auton, Didaskale, epitimēson tois mathētais sou</strong> — some of the Pharisees from the crowd said to him: Teacher, rebuke your disciples — the Pharisaic objection is to the messianic title "king" and the Hallel-citation; the messianic acclamation is publicly dangerous (Roman authorities would consider it seditious) and, in Pharisaic judgment, theologically inappropriate. <em>Epitimēson tois mathētais sou</em> (rebuke your disciples) — the same verb used for Jesus\'s rebukes of demons and fever; the Pharisees demand that Jesus silence the messianic proclamation.</p>',
    "40": '<p><strong>kai apokritheis eipen, Legō hymin, ean houtoi siōpēsousin, hoi lithoi kraxousin</strong> — answering he said: I tell you, if these keep silent, the stones will cry out — the declaration is categorical: the messianic acclamation is so intrinsic to the moment that its suppression is cosmologically impossible. <em>Hoi lithoi kraxousin</em> (the stones will cry out) — an echo of Hab 2:11 (the stones of unjust walls cry out) and the broader prophetic tradition of creation testifying to divine truth. The stones of Jerusalem — which in 40 years will be hurled down (19:44) — are here presented as potential proclaimers of the King.</p>',
    "41": '<p><strong>kai hōs ēggisen, idōn tēn polin eklausen ep autēn</strong> — when he came near, seeing the city he wept over it — <em>eklausen</em> (he wept — aorist: a specific act of weeping, not merely watering eyes; the strong word for grief-weeping, used also for the widow of Nain 7:13 and Peter 22:62). Luke is the only Gospel that records Jesus weeping over Jerusalem (Jn 11:35 records weeping over Lazarus; Mk/Mt have no parallel here). The weping occurs on the descent of the Mount of Olives as Jerusalem comes fully into view — the city of the temple, the city that kills prophets (13:34), the city he has been moving toward since 9:51.</p>',
    "42": '<p><strong>legōn hoti Ei egnōs en tē hēmera tautē kai sy ta pros eirēnēn</strong> — saying: if you had known, even you, in this day the things for peace — <em>Ei egnōs ... ta pros eirēnēn</em> (if you had known the things for peace — a second-class conditional expressing a contrary-to-fact situation: you did not know) — the lament over what might have been. <em>Ta pros eirēnēn</em> (the things for peace = what peace requires, the conditions of peace) — the shalom that the Messiah-King brings but Jerusalem cannot recognize. <strong>nyn de ekrybē apo ophthalmōn sou</strong> — but now it has been hidden from your eyes — <em>ekrybē</em> (was hidden — divine passive: God has hidden; the hardening of 8:10 applied nationally) — the opportunity has passed; the time of visitation (v.44) is closing.</p>',
    "43": '<p><strong>hoti hēxousin hēmerai epi se kai parembalousin hoi echthroi sou charaka soi</strong> — because days will come upon you when your enemies will throw up a rampart against you — Jesus\'s prediction of Jerusalem\'s siege follows the prophetic pattern of Isa 29:3 (YHWH laying siege to Ariel), Jer 6:6 (cutting down trees for siege-works), and especially Ezek 4:1-3 (the symbolic siege of Jerusalem). <em>Charax</em> (rampart, palisade of sharpened stakes — a Roman military term for circumvallation) describes precisely the siege techniques Titus used in 70 CE (Josephus, War 5.491-511): the circumvallation wall preventing escape. <em>Perikyklōsousin se</em> (will encircle you) is Josephus\'s exact language for Titus\'s siege.</p>',
    "44": '<p><strong>kai edaphiousin se kai ta tekna sou en soi</strong> — they will dash you to the ground, you and your children within you — <em>edaphizō</em> (to raze to the ground, level — from <em>edaphos</em>, the floor or ground; a rare verb for total demolition) — Josephus describes the complete leveling of Jerusalem in 70 CE (War 7.1-3). <strong>kai ouk aphēsousin en soi lithon epi lithon</strong> — and they will not leave stone upon stone in you — the precise prediction of the temple\'s destruction confirmed by Josephus (War 7.1: "the Romans led by Titus demolished the city and the sanctuary to its foundations"). <strong>anth hōn ouk egnōs ton kairon tēs episkopēs sou</strong> — because you did not recognize the time of your visitation — <em>kairos tēs episkopēs</em> (the time of visitation — <em>episkopē</em>: inspection, oversight, the official visit of a dignitary or divine messenger; cf. Isa 10:3 LXX).</p>',
    "45": '<p><strong>kai eiselthōn eis to hieron ērxato ekballein tous pōlountas</strong> — entering the temple he began to drive out those who were selling — <em>hieron</em> (the temple complex — the whole precinct, not the inner sanctuary <em>naos</em>). The sellers were in the Court of the Gentiles, selling ritually approved animals for sacrifice and exchanging foreign coins for the temple shekel required for the temple tax. Luke\'s version is the briefest of the four Gospel accounts: no mention of money-changers, doves, or buyers; simply the sellers driven out. The concision focuses on the prophetic act of cleansing rather than its commercial details.</p>',
    "46": '<p><strong>legōn autois, Gegraptai, Kai estai ho oikos mou oikos proseuchēs, hymeis de auton epoiēsate spēlaion lēstōn</strong> — saying to them: it is written: My house shall be a house of prayer; but you have made it a den of robbers — Isa 56:7 (LXX: <em>ho oikos mou oikos proseuchēs klēthēsetai pasi tois ethnesin</em> — my house will be called a house of prayer for all nations; Luke omits "for all nations," Matthew and Mark retain it) + Jer 7:11 (<em>spēlaion lēstōn</em> = den of robbers/bandits). The Jeremiah citation is from the Temple Sermon where YHWH condemned those who treated the temple as a refuge for their crimes. The "den of robbers" (<em>spēlaion lēstōn</em>) is not a comment on commercial exploitation alone but on using the temple as a hiding place — <em>lēstēs</em> means armed rebel/bandit, not petty thief.</p>',
    "47": '<p><strong>kai ēn didaskōn to kath hēmeran en tō hierō</strong> — and he was teaching daily in the temple — the imperfect <em>ēn didaskōn</em> (was teaching, continued to teach) throughout the Jerusalem period; the temple becomes Jesus\'s regular teaching platform after the entry. <strong>hoi de archiereis kai hoi grammateis ezētoun auton apoplesai kai hoi prōtoi tou laou</strong> — but the chief priests and the scribes and the principal men of the people were seeking to destroy him — <em>apōlesai</em> (to destroy, kill) — the triple coalition: <em>archiereis</em> (chief priests — the Sadducean high-priestly families), <em>grammateis</em> (scribes — the Torah experts), and <em>prōtoi tou laou</em> (the principal men of the people — the lay aristocracy) form the Jerusalem establishment.</p>',
    "48": '<p><strong>kai ouch heuriskon to ti poiēsōsin, ho laos gar hapas exekremato autou akouōn</strong> — and they could not find what they might do, for all the people were hanging on him listening — <em>exekremato autou akouōn</em> (were hanging on him listening — <em>exkremamai</em>: to hang on, be suspended from; perfect picture of rapt attention; the crowd is figuratively "hung" on Jesus\'s words, unable to be detached from him). This crowd-protection prevents immediate arrest; the authorities cannot act openly without provoking a popular uprising. The people\'s attentive hearing is the buffer between Jesus and his opponents through the Jerusalem teaching days.</p>',
  },
  "20": {
    "1": '<p><strong>kai egeneto en mia tōn hēmerōn didasontos autou ton laon en tō hierō kai euangelizomenou</strong> — one of those days as he was teaching the people in the temple and proclaiming the good news — <em>euangelizomenos</em> (proclaiming good news) paired with <em>didaskontos</em> (teaching): the twin activities of Jesus\'s Jerusalem ministry. <strong>epestēsan hoi archiereis kai hoi grammateis syn tois presbyterois</strong> — the chief priests and the scribes with the elders stood before him — the formal approach of the Jerusalem Sanhedrin: <em>archiereis</em> (high priests), <em>grammateis</em> (scribes), and <em>presbyteroi</em> (elders) constitute the three components of the Sanhedrin (cf. Mk 14:53; Acts 4:5). Their standing (<em>epestēsan</em>) before him in the temple court is an official confrontation.</p>',
    "2": '<p><strong>kai eipan legontes pros auton, Eipov hēmin, en poia exousia tauta poieis, ē tis estin ho dous soi tēn exousian tautēn</strong> — they said to him: tell us by what authority you do these things, or who is the one who gave you this authority — the double-form of the question covers both the question of kind (<em>en poia exousia</em> = in what kind of authority) and the question of source (<em>tis estin ho dous</em> = who gave it). The temple cleansing (19:45-46) and the continuing teaching are both in view. <em>Exousia</em> (authority) — the same word that amazed the synagogue in Capernaum (4:32); now the Jerusalem leadership demands its authorization. Without rabbinic credentials, a priestly appointment, or official commission, Jesus\'s authority was unexplained by normal categories.</p>',
    "3": '<p><strong>apokritheis de eipen pros autous, Erōtēsō hymas kagō logon, kai eipate moi</strong> — he answered and said to them: I also will ask you a word; tell me — the counter-question is the Socratic-rabbinic device of answering a question with a question. <em>Kagō erōtēsō hymas</em> (I also will ask you — the <em>kai</em> + <em>egō</em> is emphatic: I too, not just you, will ask) makes the exchange symmetrical and competitive. The counter-question is not evasion but a revelatory move: Jesus\'s question about John forces the authorities to reveal the epistemological framework that renders his authority question unanswerable.</p>',
    "4": '<p><strong>To baptisma Iōannou ex ouranou ēn ē ex anthrōpōn</strong> — John\'s baptism — was it from heaven or from men? — the dilemma is perfectly constructed. <em>Ex ouranou</em> (from heaven) = divinely authorized (heaven is the Semitic circumlocution for God, cf. 15:18); <em>ex anthrōpōn</em> (from human origin) = self-claimed without divine commission. John\'s baptism was universally acknowledged as morally powerful (3:10-14; 7:29-30) and his credentials as a prophet were established. The question forces the Jerusalem establishment to take a position on divine authority — the same category in which Jesus operates.</p>',
    "5": '<p><strong>hoi de synelogisanto pros heautous legontes hoti Ean eipōmen, Ex ouranou, erei, Dia ti ouk episteusate autō</strong> — they deliberated with one another saying: if we say, From heaven, he will say, Why did you not believe him? — <em>synelogisanto</em> (deliberated together — the compound prefix <em>syn-</em> indicates shared deliberation; <em>logizomai</em> = to calculate, reason; the council calculates its options). The first horn of the dilemma: affirming John\'s divine authorization immediately requires explaining why they did not respond to his baptism — a damning admission. <em>Episteuein</em> (to believe, trust, respond in faith) to John meant submitting to his call to repentance and his baptism.</p>',
    "6": '<p><strong>ean de eipōmen, Ex anthrōpōn, ho laos hapas katalithasei hēmas</strong> — but if we say, From men, all the people will stone us — <em>katalithasō</em> (to stone, stone to death) — the crowd\'s conviction of John\'s prophetic status (3:15; 7:29-30) made any denial of his divine authorization dangerous. <strong>pepeismenoi gar eisin Iōannēn prophētēn einai</strong> — for they are convinced that John is a prophet — <em>pepeismenos</em> (perfect passive participle: having been persuaded and remaining convinced) — the crowd\'s conviction about John is settled; it cannot be moved by the authorities\' denial. The second horn is politically fatal.</p>',
    "7": '<p><strong>kai apekrithēsan mē eidenai pothen</strong> — they answered that they did not know where it was from — the authorities\' non-answer is an admission of epistemological paralysis or dishonest calculation. They do not say "we don\'t know" because they are genuinely uncertain; they refuse to answer to preserve their political position. The public non-answer in the temple courts, before "all the people" (v.9), is a public humiliation: the recognized religious authorities of Israel cannot or will not answer a question about John\'s authority.</p>',
    "8": '<p><strong>kai ho Iēsous eipen autois, Oude egō legō hymin en poia exousia tauta poiō</strong> — and Jesus said to them: neither will I tell you by what authority I do these things — the response is symmetrical: they will not answer his question; he will not answer theirs. But the exchange has already answered the question: if they cannot evaluate John\'s authority (which Jesus implicitly identifies as the same category as his own), they lack the framework to evaluate Jesus\'s authority. The non-answer is the answer: Jesus\'s authority is from heaven, as John\'s was — the source they refused to acknowledge.</p>',
    "9": '<p><strong>Ērxato de pros ton laon legein tēn parabolēn tautēn</strong> — he began to tell the people this parable — the audience shifts from the authorities (vv.1-8) to the people (<em>laos</em>); the parable is told publicly, not privately. <strong>Anthrōpos ephyteusen ampelōna</strong> — a man planted a vineyard — the vineyard is Israel\'s classic OT symbol (Isa 5:1-7; Ps 80:8-16; Jer 2:21); the allusion is immediate for those familiar with the Isaianic "Song of the Vineyard." <strong>kai exedeto auton geōrgois</strong> — and rented it to farmers — <em>geōrgoi</em> (farmers, tenant-farmers) — the tenants who receive the vineyard on lease and owe the owner a share of the harvest; in the allegorical reading, the tenant-farmers are Israel\'s leaders responsible for the covenant community. <strong>kai apedēmēsen chronous hikanous</strong> — and went away for a long time.</p>',
    "10": '<p><strong>kai en kairō apesteilen pros tous geōrgous doulon hina apo tou karpou tou ampelōnos dōsousin autō</strong> — at the proper time he sent a servant to the farmers so they would give him some of the fruit of the vineyard — <em>en kairō</em> (at the appointed time, the right time — harvest season) signals the legitimate expectation of return. The servant represents the prophetic emissaries sent to Israel throughout its history. <strong>hoi de geōrgoi exapesteilan auton deirantes kenon</strong> — but the farmers beat him and sent him away empty-handed — <em>deirō</em> (to beat, flay — the word for flogging; the same used in 12:47-48 for punishment) and <em>kenon</em> (empty — without the fruit owed). The pattern of prophetic rejection: sent, beaten, dismissed.</p>',
    "11": '<p><strong>kai prosetheto heteron pempsa doulon, hoi de kakeinon deirantes kai atimasantes exapesteilan kenon</strong> — and he proceeded to send another servant; them also beating and dishonoring him they sent away empty-handed — <em>prosetheto ... pempsa</em> (he added, he proceeded to send — the idiomatic Lukan construction for sequential action; cf. 20:12). <em>Atimasantes</em> (dishonoring — treating with contempt, stripping of honor) adds a dimension beyond physical beating: the servant is publicly shamed, a serious violation in an honor-shame culture. The prophetic-rejection pattern continues: each emissary receives worse treatment.</p>',
    "12": '<p><strong>kai prosetheto triton pempsa, hoi de kai touton traumatisantes exebalon</strong> — he proceeded to send a third, and they also wounding this one threw him out — <em>traumatizō</em> (to wound — from <em>trauma</em>, wound; a medical term Luke employs precisely) is a more severe injury than beating (<em>deirō</em> in vv.10-11); escalating violence. <em>Exebalon</em> (threw him out, cast him outside) removes him from the vineyard itself — the escalation from dismissal to expulsion. The three-servant sequence recalls the three-year search for fruit (13:7) and generally represents the full prophetic history of Israel.</p>',
    "13": '<p><strong>eipen de ho kyrios tou ampelōnos, Ti poiēsō</strong> — the lord of the vineyard said: what shall I do? — the owner\'s self-deliberation (an internal monologue, as in the Rich Fool 12:17) reveals not weakness but the extraordinary patience of one who has extended every reasonable option. <strong>Pempsō ton huion mou ton agapēton</strong> — I will send my beloved son — <em>ton huion ton agapēton</em> (the beloved son) — the exact phrase from the baptism voice (3:22: <em>su ei ho huios mou ho agapētos</em>) and the Transfiguration (9:35: <em>ho huios mou ho eklelegmenos</em>). The allegorical identification is transparent: the owner\'s beloved son is the Son whom God sent. <em>Isōs touton entrapēsontai</em> — perhaps they will respect him (entrepō: to turn toward, show regard for, feel shame before).</p>',
    "14": '<p><strong>idontes de auton hoi geōrgoi dielogizonto pros allēlous legontes, Houtos estin ho klēronomos</strong> — seeing him, the farmers deliberated with one another: this is the heir — <em>dielogizonto</em> (deliberated, reasoned among themselves — the sinister planning of those who recognize the heir and see an opportunity). <em>Klēronomos</em> (heir, inheritor — the one who will inherit the estate upon the owner\'s death) — the tenants\' recognition of the heir is paradoxical: knowing who he is does not produce submission but determines the plan of murder. <strong>apokteinōmen auton, hina hēmōn genētai hē klēronomia</strong> — let us kill him so that the inheritance may become ours — the logic of seizure: remove the heir, become heirs yourselves. The greed of the tenants has become murderous.</p>',
    "15": '<p><strong>kai ekbalontes auton exō tou ampelōnos apekteinan</strong> — throwing him out of the vineyard they killed him — the sequence is significant: <em>ekbalontes exō tou ampelōnos</em> (throwing him outside the vineyard) before killing recalls Heb 13:12 ("Jesus also suffered outside the gate to sanctify the people through his own blood") — crucified outside Jerusalem\'s walls. The allegory maps precisely: the son killed outside the vineyard = the Messiah crucified outside the city. <strong>ti oun poiēsei autois ho kyrios tou ampelōnos</strong> — what then will the lord of the vineyard do to them? — the question Jesus poses to the audience, inviting them to judge the tenants and thereby judge themselves.</p>',
    "16": '<p><strong>eleusetai kai apolesei tous geōrgous toutous kai dōsei ton ampelōna allois</strong> — he will come and destroy those farmers and give the vineyard to others — the judgment on the tenants (the Jerusalem leadership) and the transfer of stewardship ("give to others") points to the post-resurrection mission: the vineyard\'s management passes from the temple establishment to the apostolic community. <strong>akousantes de eipan, Mē genoito</strong> — hearing this, they said: may it never be! — <em>Mē genoito</em> (may it not happen! — the strongest Greek negative wish, Paul\'s characteristic "by no means!" in Romans; LXX: <em>mē genoito</em> for "God forbid"). The audience recoils from the judgment they have just endorsed.</p>',
    "17": '<p><strong>ho de emblepsas autois eipen, Ti oun estin to gegrammenon touto</strong> — looking at them he said: what then is this that is written? — <em>emblepsas</em> (looking intently, fixing his gaze on them) — the penetrating gaze that follows their protest. <strong>Lithon hon apedokimasan hoi oikodomomountes, houtos egenēthē eis kephalēn gōnias</strong> — The stone which the builders rejected, this became the cornerstone — Ps 118:22 (LXX) — the rejection-of-the-builder\'s-stone is a wisdom paradox: the builders are experts in judging stone quality, yet the stone they discarded as unsuitable becomes the <em>kephalē gōnias</em> (head/top of the corner — either the cornerstone at the foundation or the capstone at the top of an arch; either way, the structurally critical stone). The Psalm citation was already used in v.38 (Ps 118:26); Jesus uses Psalm 118 as a unity.</p>',
    "18": '<p><strong>pas ho pesōn ep ekeinon ton lithon synthlastesetai</strong> — everyone falling on that stone will be shattered — <em>synthlō</em> (to shatter, crush to pieces) — the stone that is the cornerstone is also a stone of stumbling (cf. Isa 8:14; Rom 9:32-33; 1 Pet 2:8). <strong>eph hon d an pesē, likmēsei auton</strong> — and on whomever it falls, it will crush him to powder — <em>likmaō</em> (to winnow, scatter like chaff; then, to grind to powder) — the image moves from stumbling to being crushed by a falling stone; both describe the catastrophic consequences of rejecting the Messiah-cornerstone. Dan 2:44 (the stone that grinds the statue to powder) is the background.</p>',
    "19": '<p><strong>kai ezētēsan hoi grammateis kai hoi archiereis epibalein ep auton tas cheiras en autē tē hōra</strong> — the scribes and chief priests sought to lay hands on him in that very hour — the authorities recognize themselves as the tenants of the parable; the immediate consequence is intensified desire for arrest. <em>En autē tē hōra</em> (in that very hour) — the recognition of the allegory\'s target produces instant hostility. <strong>kai ephobēthēsan ton laon</strong> — and they feared the people — the same crowd-protection as 19:48; the popular regard for Jesus prevents open action. <strong>egnōsan gar hoti pros autous tēn parabolēn tautēn eipen</strong> — for they knew that he spoke this parable against them.</p>',
    "20": '<p><strong>kai paratērēsantes apesteilan enkathetus hypokrinoumenous heautous dikaiious einai</strong> — watching closely they sent spies pretending to be righteous — <em>enkathetos</em> (a spy, a plant in the audience — literally "one set in place secretly"; the only NT use of this word) underlines the deliberate deception. <em>Hypokrinoumenous heautous dikaiious einai</em> (pretending to be righteous — <em>hypokrinō</em> = to play a role, act; they perform righteousness while pursuing entrapment). <strong>hina epilabōntai autou logou, hōste paradounai auton tē archē kai tē exousia tou hēgemonos</strong> — in order to catch him in a word, so as to deliver him to the authority and power of the governor — <em>hēgemon</em> (governor — the Roman Prefect/Procurator; Pontius Pilate) — the goal is to get a statement that constitutes <em>maiestas</em> (Roman treason).</p>',
    "21": '<p><strong>kai epērōtēsan auton legontes, Didaskale, oidamen hoti orthōs legeis kai didaskeis kai ou lambaneis prosōpon</strong> — they questioned him saying: Teacher, we know that you speak and teach correctly and do not accept personal appearances — <em>ou lambaneis prosōpon</em> (you do not take up a face = you do not show partiality, you do not play favorites; <em>prosōpolēpsia</em> is the NT term for favoritism) — the flattery establishes what they hope he will demonstrate: honest speech regardless of political consequences. <strong>all ep alētheias tēn hodon tou Theou didaskeis</strong> — but you teach the way of God according to truth — <em>tēn hodon tou Theou</em> (the way of God) is used later for the Christian movement itself (Acts 9:2; 19:9,23; 22:4; 24:14,22).</p>',
    "22": '<p><strong>Exestin hēmin Kaisari phoron dounai ē ou</strong> — is it lawful for us to pay taxes to Caesar or not? — <em>phoros</em> (tribute, direct tax — the provincial head-tax levied by Rome on subject peoples, distinct from the <em>telos</em>/toll which was indirect). The question is a political trap: answer "yes" and Jesus alienates the Jewish nationalist crowd who resented Roman tribute; answer "no" and he commits sedition against Rome. The Zealot movement had been founded on the principle that paying tribute to Caesar was treason against YHWH\'s sole kingship over Israel (Josephus, Ant. 18.23).</p>',
    "23": '<p><strong>katanosas de autōn tēn panourgiav eipen pros autous</strong> — perceiving their craftiness he said to them — <em>katanoeō</em> (to perceive thoroughly, observe carefully — the same word for contemplating the ravens in 12:24 and the speck in 6:41) applied to the detection of malicious intent. <em>Panourgia</em> (craftiness, unscrupulous cunning — from <em>pan</em> + <em>ergon</em>: doing everything/anything to achieve one\'s end; a morally negative term in biblical usage, cf. 1 Cor 3:19; 2 Cor 4:2) — Jesus names their scheme before addressing it.</p>',
    "24": '<p><strong>Deixate moi dēnarion; tinos echei eikona kai epigraphēn</strong> — show me a denarius; whose image and inscription does it have? — <em>dēnarion</em> (a Roman silver coin worth a day\'s wage for a laborer; the standard wage in Mt 20:2). The Tiberian denarius bore an obverse image (<em>eikōn</em>) of Tiberius Caesar with the inscription TI CAESAR DIVI AVG F AVGVSTVS (Tiberius Caesar, Son of the Divine Augustus) and a reverse image of the seated <em>Pontifex Maximus</em>. <em>Eikōn kai epigraphē</em> (image and inscription) — the coin carries both the ruler\'s portrait and his title. <strong>hoi de eipan, Kaisaros</strong> — they said: Caesar\'s.</p>',
    "25": '<p><strong>ho de eipen pros autous, Toinyv apodote ta Kaisaros Kaisari kai ta tou Theou tō Theō</strong> — he said to them: then give back to Caesar what is Caesar\'s and to God what is God\'s — <em>apodidōmi</em> (to give back, return, pay what is owed — not merely "give" but "return what belongs to another") is the key verb: both Caesar\'s coin and God\'s image-bearers are to be returned to their rightful owners. The answer does not resolve the tension between political obligation and theological sovereignty but disarms the trap: using Caesar\'s coin implies operating within his economic system; operating within his system entails some obligation. The distinction between Caesar\'s sphere and God\'s sphere is left unstated — its content is the ongoing theological question.</p>',
    "26": '<p><strong>kai ouk ischysan epilabesthai autou rēmatos enantov tou laou</strong> — they were unable to catch him in his word before the people — <em>epilambanō</em> (to catch, seize, lay hold of — here used for verbal trapping) — the trap failed. <strong>kai thaumasantes epi tē apokrisei autou esigesav</strong> — and marveling at his answer they fell silent — <em>thaumazontes</em> (marveling, astonished) indicates genuine surprise; the questioners had not anticipated the answer\'s elegance. <em>Esigesan</em> (they fell silent — aorist: a sudden complete silence) marks the end of this line of attack; the spies withdraw defeated.</p>',
    "27": '<p><strong>Proselthontes de tines tōn Saddoukaiōn, hoi antilegontes anastasin mē einai</strong> — approaching, some of the Sadducees, who deny that there is a resurrection — Luke\'s parenthetical gloss on the Sadducees (<em>antilegontes anastasin mē einai</em> = saying in opposition that there is no resurrection) is a reader-orientation note for Gentile audiences unfamiliar with the Sadducean position. The Sadducees accepted only the written Torah (Pentateuch) as authoritative and rejected the Pharisaic oral tradition and doctrines of resurrection and angels (Acts 23:8). The resurrection debate places Jesus squarely in agreement with the Pharisees against the Sadducean aristocratic priesthood.</p>',
    "28": '<p><strong>epērōtēsan auton legontes, Didaskale, Mōysēs egrapsen hēmin</strong> — questioned him saying: Teacher, Moses wrote for us — the opening invocation of Moses\'s written authority signals Sadducean method: scripture (specifically Torah) is the basis of the argument. <strong>ean tinos adelphos apothanē echōn gynaika kai houtos ateknos ē, hina labē ho adelphos autou tēn gynaika kai exanastēsē sperma tō adelphō autou</strong> — if a man\'s brother dies having a wife and he is childless, the brother should take the wife and raise up offspring for his brother — Deut 25:5-10 (levirate marriage, <em>yibbum</em>): the obligation of the surviving brother to marry the widow and produce an heir for the deceased brother\'s name.</p>',
    "29": '<p><strong>hepta oun adelphoi ēsan</strong> — there were seven brothers — the number seven (<em>hepta</em>) is deliberately extreme: a maximally absurd scenario designed to expose the resurrection doctrine as logically incoherent within their reductio ad absurdum. The Sadducees construct a case that makes resurrection appear to violate Mosaic law (a woman cannot simultaneously be married to seven husbands). <strong>kai ho prōtos labōn gynaika apethanen ateknos</strong> — and the first married a woman and died childless — <em>ateknos</em> (childless, without offspring — from <em>a-</em> + <em>teknon</em>) activates the levirate obligation for the second brother.</p>',
    "30": '<p><strong>kai ho deuteros</strong> — and the second — Luke\'s brief notation (vs. Matthew and Mark\'s slightly fuller version) of the second brother\'s marriage and death. The pattern is established by the first brother and repeated six times: marry, die childless, leaving the widow for the next. Luke\'s compressed account of brothers two through six (vv.30-31) is characteristic of his editorial economy when the point is established; the reader understands the pattern without full repetition.</p>',
    "31": '<p><strong>kai ho tritos elaben autēn, hōsautōs de kai hoi hepta ou katélipon tekna kai apethanon</strong> — the third took her, and likewise also all seven left no children and died — <em>hōsautōs</em> (in the same way, likewise) abbreviates the repetition; the pattern holds through all seven brothers. <em>Ou katelipon tekna</em> (left no children) — the levirate obligation was never fulfilled; no heir was produced. The scenario is designed to be maximally embarrassing for resurrection doctrine: if she is resurrected, she simultaneously belongs to seven husbands under Moses\'s law.</p>',
    "32": '<p><strong>hysteron kai hē gynē apethanen</strong> — finally the woman also died — the widow\'s death (last in the sequence) completes the scenario. All eight principals (seven brothers + the widow) have died, creating the theoretical resurrection problem. The Sadducean question assumes: (a) resurrection involves resurrection of the same relational configuration as earthly life, and (b) therefore levirate marriage creates an insoluble legal problem in the resurrection. Both assumptions Jesus will correct.</p>',
    "33": '<p><strong>hē gynē oun en tē anastasei, tinos autōn ginetai gynē</strong> — in the resurrection therefore, whose wife will she be? for the seven had her as wife — the question is the payoff of the elaborate scenario: <em>tinos autōn ginetai gynē</em> (of which of them does she become wife? — the present <em>ginetai</em> makes it an ongoing relational question, not merely a legal technicality). The scenario assumes that resurrection implies continuation of earthly legal statuses; the answer will challenge this assumption fundamentally.</p>',
    "34": '<p><strong>kai eipen autois ho Iēsous, Hoi huioi tou aiōnos toutou gamousin kai gamiskontai</strong> — Jesus said to them: the sons of this age marry and are given in marriage — <em>hoi huioi tou aiōnos toutou</em> (the sons of this age — Lukan term for those whose life is defined by the present age, as opposed to the sons of the coming age in v.35). <em>Gamousin kai gamiskontai</em> (marry and are given in marriage — the active and passive of the wedding: men take wives; women are given by fathers) — marriage is the institutional structure of the present mortal age, necessary for biological continuity through death.</p>',
    "35": '<p><strong>hoi de kataxiōthentes tou aiōnos ekeinou tychein kai tēs anastaseōs tēs ek nekrōn</strong> — but those who are counted worthy of that age and of the resurrection from the dead — <em>kataxiōthentes</em> (those counted worthy, deemed worthy — the divine passive indicating God\'s judgment of fitness for the age to come) — the resurrection life is not automatic or universal in Jesus\'s framing but a qualification (<em>axios</em> = worthy; the same root as in Mt 10:37-38). <strong>oute gamousin oute gamizontai</strong> — neither marry nor are given in marriage — the resurrection life does not require marriage because its biological-continuity function (producing offspring to carry on after death) is rendered obsolete when death itself is abolished (v.36).</p>',
    "36": '<p><strong>oude gar apothanein eti dynantai, isangeloi gar eisin kai huioi eisin Theou tēs anastaseōs huioi ontes</strong> — for they can no longer die; for they are like angels and are sons of God, being sons of the resurrection — <em>isangeloi</em> (like/equal to angels — a compound hapax in the NT; the only NT description of the resurrection state as angel-like) — not that humans become angels but that they share the angels\' deathlessness. <em>Apothanein eti dynantai</em> (they can no longer die) — the abolition of death (1 Cor 15:26; Rev 21:4) removes the need for marriage\'s biological function. <em>Huioi Theou</em> (sons of God) — in the resurrection, the divine-adoption that believers receive now (Rom 8:14-17; Gal 4:6-7) reaches its fullness.</p>',
    "37": '<p><strong>hoti de egeirontai hoi nekroi, kai Mōysēs emēnusen epi tēs batou, hōs legei Kyrion ton Theon Abraam kai Theon Isaak kai Theon Iakōb</strong> — that the dead are raised, even Moses showed in the passage about the burning bush, as he calls the Lord the God of Abraham and the God of Isaac and the God of Jacob — Jesus uses Sadducean methodology against them: they accept only Moses; Moses himself teaches resurrection. The burning bush passage is Exod 3:6. The argument is grammatical and theological: YHWH identifies himself in the present tense (<em>egō eimi</em>) as the God of three patriarchs who were already long dead by Moses\'s time. YHWH\'s self-identification with the living patriarchs implies they are alive to him.</p>',
    "38": '<p><strong>theos de ouk estin nekrōn alla zōntōn, pantes gar autō zōsin</strong> — he is not the God of the dead but of the living, for all are alive to him — the theological principle derived from Exod 3:6: YHWH\'s covenant relationship with the patriarchs is a present reality, not merely a historical record. <em>Pantes gar autō zōsin</em> (for all are alive to him) — the phrase may mean "all will be alive in his sight at the resurrection" (proleptic) or "all are already alive in his perspective" (eternal present); both support the resurrection. The argument is from the nature of God as covenant-keeper: a God who identifies himself by his relationship with people maintains that relationship, including through death.</p>',
    "39": '<p><strong>apokrithentes de tines tōn grammateōn eipan, Didaskale, kalōs eipas</strong> — some of the scribes answered: Teacher, well said — the scribes\' approval (<em>kalōs eipas</em> = you spoke well, beautifully) reflects the Pharisaic scribes\' agreement with the resurrection teaching against the Sadducees. The cross-party dynamics of Jerusalem: the scribes (typically Pharisaic) enjoy Jesus\'s defeat of the Sadducees. The momentary alliance of scribal approval does not mean acceptance of Jesus as Messiah; it means the argument about resurrection was compelling and scored against a theological opponent.</p>',
    "40": '<p><strong>ouketi gar etolmōn eperōtan auton ouden</strong> — for they no longer dared to ask him anything — <em>etolmaō</em> (to dare, have the courage — implying that questions now involved too much risk of public defeat; the authorities\' line of interrogation has been exhausted). Three challenges have failed: the authority question (vv.1-8), the tax question (vv.20-26), and the resurrection question (vv.27-38). Jesus has answered all three in ways that expose his questioners and silence further inquiry. The silence signals the shift of initiative: Jesus now asks the question (v.41).</p>',
    "41": '<p><strong>Eipen de pros autous, Pōs legousin ton Christon einai Dauid huion</strong> — he said to them: how do they say the Messiah is David\'s son? — Jesus now takes the offensive with a Christological question about David\'s descendant. <em>Pōs legousin</em> (how do they say) — the impersonal "they" refers to scribal teaching; the expectation was that the Messiah would be a Davidic descendant (2 Sam 7:12-16; Isa 11:1-10; Jer 23:5-6; Ezek 37:24-25). This is not in dispute; what Jesus raises is whether "son of David" adequately describes the Messiah\'s nature and identity.</p>',
    "42": '<p><strong>autos gar Dauid legei en biblō Psalmōn</strong> — for David himself says in the Book of Psalms — <em>en biblō Psalmōn</em> (in the Book of Psalms — Luke uses this fuller designation vs. Matthew/Mark\'s "David himself said in the Spirit"). Ps 110:1 is the most frequently cited OT text in the NT (Mt 22:44; Mk 12:36; Acts 2:34-35; Heb 1:13; 10:13; 1 Pet 3:22; Rev 3:21). <strong>Eipen Kyrios tō Kyriō mou, Kathou ek dexiōn mou</strong> — the Lord said to my Lord: sit at my right hand — <em>Kyrios ... tō Kyriō mou</em> — the LXX renders <em>YHWH</em> as <em>Kyrios</em> and <em>Adonai</em> also as <em>Kyrios</em>; David\'s "my Lord" (his Adonai) is thus addressed by YHWH himself, creating two divine referents.</p>',
    "43": '<p><strong>heōs an thō tous echthrous sou hypopodion tōn podōn sou</strong> — until I make your enemies a footstool for your feet — Ps 110:1b — the footstool image (<em>hypopodion</em>) is the posture of total subjection: conquered enemies placed under the feet of the victor (Josh 10:24; Ps 8:6). The waiting posture ("sit at my right hand until") implies an interim period between the enthronement and the completion of the subjection — precisely the period of the church\'s mission in Acts. The enemies\' subjection is the Father\'s action, not the enthroned Son\'s; the Son waits and reigns while the Father acts.</p>',
    "44": '<p><strong>Dauid oun auton Kyrion kalei, kai pōs autou huios estin</strong> — David therefore calls him Lord; how then is he his son? — the dilemma Jesus poses: if David calls the Messiah "my Lord" (<em>Kyrios</em>), the Messiah cannot be merely David\'s descendant in the ordinary sense (descendants were never "lord" over their ancestors in ancient Near Eastern culture; the social flow ran the other direction). The question does not deny Davidic descent (Luke\'s genealogy has just established it, 3:31) but insists that Davidic sonship does not exhaust the Messiah\'s identity. Jesus does not answer the question; he leaves the Christological implication for the audience to resolve.</p>',
    "45": '<p><strong>Akouontos de pantos tou laou eipen tois mathētais autou</strong> — while all the people were listening he said to his disciples — the public setting ("all the people listening") and the directed address ("to his disciples") creates a dual audience: the warning about the scribes is given to disciples but intended for the crowd to overhear. <em>Pantos tou laou</em> (all the people) is the full Jerusalem crowd that has been listening throughout the temple controversy.</p>',
    "46": '<p><strong>Prosechete apo tōn grammateōn tōn thelontōn peripatein en stolais kai philountōn aspasmous en tais agorais kai prōtokathedrias en tais synagōgais kai prōtoklisias en tois deipnois</strong> — beware of the scribes who like to walk around in long robes and love greetings in the marketplaces and the first seats in the synagogues and the first places at banquets — three markers of honor-seeking: <em>stolai</em> (long, flowing robes — the distinctive dress of scribal scholars that signaled status; cf. Mk 12:38), <em>aspasmoi en tais agorais</em> (greetings/salutations in the public squares — public deferential address), <em>prōtokathedriai</em> (first/front seats of honor in synagogues) and <em>prōtoklisiai</em> (first reclining-places, the host\'s-right positions at banquets — the highest-honor dining positions).</p>',
    "47": '<p><strong>hoi katesthiousin tas oikias tōn chērōn kai prophasei makra proseuchontai</strong> — who devour the houses of widows and for a pretext make long prayers — <em>katesthiousin tas oikias tōn chērōn</em> (devour the houses of widows) — the consumption of widows\' estates while acting as religious advisors or executors of estates; a form of economic exploitation beneath a veneer of piety (cf. Isa 10:2; Ezek 22:25). <em>Prophasis</em> (pretext, cover, facade — prayer used as a reputation-building display rather than sincere address to God). <strong>houtoi lēpsontai perissoteron krima</strong> — these will receive greater judgment — <em>perissoteron krima</em> (more judgment, greater condemnation — the proportional accountability principle of 12:47-48 applied to religious leaders who exploit their position). The scribal warning closes the Jerusalem controversy section.</p>',
  }
}

def main():
    existing = load_comm('mkt-original', 'luke')
    merge_comm(existing, LUKE)
    save_comm('mkt-original', 'luke', existing)
    print('Luke mkt-original chs 19-20 written.')

if __name__ == '__main__':
    main()
